class TestDatabase(unittest.TestCase):
    _cache = {}

    def test_user_creation(self):
        self._cache['test_user'] = create_user('test@example.com')
        assert self._cache['test_user'].id > 0

    def test_user_deletion(self):
        user = self._cache.get('test_user')
        if user:
            delete_user(user.id)
        assert user is None
